import{_ as s,o as n,c as e,aQ as i}from"./chunks/framework.cDvftfeu.js";const k=JSON.parse('{"title":"Ham Web","description":"Ham Webフロントエンドのアーキテクチャと機能。","frontmatter":{"description":"Ham Webフロントエンドのアーキテクチャと機能。","prev":{"text":"ブランドリソース","link":"/ja/developers/open-platform/brand-assets"},"next":{"text":"SSO OAuth2 認証","link":"/ja/developers/ham-web/sso-authorize"}},"headers":[],"relativePath":"ja/developers/ham-web/index.md","filePath":"ja/developers/ham-web/index.md","lastUpdated":1777525243000}'),l={name:"ja/developers/ham-web/index.md"};function t(p,a,o,r,h,d){return n(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="ham-web" tabindex="-1">Ham Web <a class="header-anchor" href="#ham-web" aria-label="Permalink to &quot;Ham Web&quot;">​</a></h1><p><a href="https://github.com/whu-ham/ham-web" target="_blank" rel="noreferrer">Ham Web</a> は Ham の Web フロントエンドプロジェクトで、主に SSO シングルサインオン認証フローを提供し、Ham Connect プラットフォームの Web エントリーポイントとして機能します。</p><h2 id="使用場所" tabindex="-1">使用場所 <a class="header-anchor" href="#使用場所" aria-label="Permalink to &quot;使用場所&quot;">​</a></h2><p>Ham Web はデプロイ後、Ham Connect プラットフォームの Web サービスエンドポイントとして機能します。主に以下のシナリオで使用されます：</p><ul><li><strong>SSO 認証ページ</strong> — サードパーティアプリが Ham Connect プラットフォームを通じて OAuth2 認証を開始すると、ユーザーは Ham Web の認証ページにリダイレクトされ、ログインと同意確認を行います</li><li><strong>QR コードログイン</strong> — ユーザーは Web 上で QR コードをスキャンしてログインできます</li><li><strong>Passkey ログイン</strong> — WebAuthn / Passkey パスワードレスログインをサポート</li><li><strong>モバイル H5 フォールバック</strong> — Ham ネイティブアプリがインストールされていない場合、Web ベースのインストール案内と Passkey ログインオプションを提供</li></ul><h2 id="技術スタック" tabindex="-1">技術スタック <a class="header-anchor" href="#技術スタック" aria-label="Permalink to &quot;技術スタック&quot;">​</a></h2><ul><li><strong>フレームワーク</strong>: Next.js 16（App Router）+ React 19 + TypeScript</li><li><strong>スタイリング</strong>: Tailwind CSS v4 + HeroUI v3</li><li><strong>状態管理</strong>: Jotai + React Redux</li><li><strong>国際化</strong>: next-intl（中国語 / 英語 / 日本語）</li><li><strong>デプロイ</strong>: Cloudflare Pages（OpenNext 経由）</li><li><strong>ツールチェーン</strong>: ESLint v9 + Prettier + pnpm</li></ul><h2 id="はじめに" tabindex="-1">はじめに <a class="header-anchor" href="#はじめに" aria-label="Permalink to &quot;はじめに&quot;">​</a></h2><h3 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h3><ul><li>Node.js &gt;= 20</li><li>pnpm</li></ul><h3 id="インストールと実行" tabindex="-1">インストールと実行 <a class="header-anchor" href="#インストールと実行" aria-label="Permalink to &quot;インストールと実行&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 依存関係のインストール</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 開発サーバーの起動（Turbopack）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># プロダクションビルド</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Cloudflare Pages ビルド</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:cf</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># リント</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lint</span></span></code></pre></div><p>開発サーバーは <code>http://localhost:3000</code> で実行されます。</p><h2 id="プロジェクト構成" tabindex="-1">プロジェクト構成 <a class="header-anchor" href="#プロジェクト構成" aria-label="Permalink to &quot;プロジェクト構成&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/                # Next.js App Router エントリー</span></span>
<span class="line"><span>  api/              # API ルート</span></span>
<span class="line"><span>    auth/           # 認証関連 API（ログイン、ログアウト、リフレッシュ、Passkey、QR コード）</span></span>
<span class="line"><span>    sso/            # SSO 関連 API（同意確認、同意情報）</span></span>
<span class="line"><span>  sso-authorize/    # SSO 認証ページ（ログインビュー、QR ログイン、Passkey ログイン）</span></span>
<span class="line"><span>components/         # 共有 UI コンポーネント</span></span>
<span class="line"><span>  LanguageSwitcher  # 言語切り替え</span></span>
<span class="line"><span>  ThemeSwitcher     # テーマ切り替え</span></span>
<span class="line"><span>  SearchBar         # 検索バー</span></span>
<span class="line"><span>i18n/               # next-intl ランタイム設定</span></span>
<span class="line"><span>messages/           # 多言語翻訳ファイル（en.json / zh.json / ja.json）</span></span>
<span class="line"><span>services/           # API / サービス層</span></span>
<span class="line"><span>store/              # 状態管理（ロケール、テーマ）</span></span>
<span class="line"><span>public/             # 静的アセット</span></span></code></pre></div><h2 id="開発ガイド" tabindex="-1">開発ガイド <a class="header-anchor" href="#開発ガイド" aria-label="Permalink to &quot;開発ガイド&quot;">​</a></h2><h3 id="新しい-ui-文字列の追加" tabindex="-1">新しい UI 文字列の追加 <a class="header-anchor" href="#新しい-ui-文字列の追加" aria-label="Permalink to &quot;新しい UI 文字列の追加&quot;">​</a></h3><p>国際化には <code>next-intl</code> を使用します。新しい文字列を追加する際は、3 つの翻訳ファイルすべてを更新してください：</p><ul><li><code>messages/zh.json</code></li><li><code>messages/en.json</code></li><li><code>messages/ja.json</code></li></ul><h3 id="api-ルート" tabindex="-1">API ルート <a class="header-anchor" href="#api-ルート" aria-label="Permalink to &quot;API ルート&quot;">​</a></h3><p>Ham Web の API ルートはバックエンドプロキシとして機能し、リクエストを Ham バックエンドサービスに転送します：</p><ul><li><code>/api/auth/*</code> — 認証関連（ログイン、ログアウト、トークンリフレッシュ、Passkey、QR コード）</li><li><code>/api/sso/*</code> — SSO 認証関連（同意情報照会、同意確認）</li></ul><h3 id="テーマと言語" tabindex="-1">テーマと言語 <a class="header-anchor" href="#テーマと言語" aria-label="Permalink to &quot;テーマと言語&quot;">​</a></h3><ul><li>ライト / ダーク / システム連動の 3 つのテーマモードをサポート</li><li>中国語 / 英語 / 日本語の 3 言語をサポートし、Cookie でユーザー設定を永続化</li></ul><h2 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h2><p>プロジェクトは GitHub Actions で継続的インテグレーションを行い、Cloudflare Pages にデプロイされます。</p><h2 id="コントリビューションガイド" tabindex="-1">コントリビューションガイド <a class="header-anchor" href="#コントリビューションガイド" aria-label="Permalink to &quot;コントリビューションガイド&quot;">​</a></h2><p>すべてのコントリビューターは以下のルールに従う必要があります：</p><ol><li>コミット前に <code>pnpm lint</code> と <code>pnpm build</code> を実行すること</li><li>コミットメッセージは <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a> に従うこと</li><li>コミットメッセージとコードコメントは英語で記述すること</li></ol><h2 id="ライセンス" tabindex="-1">ライセンス <a class="header-anchor" href="#ライセンス" aria-label="Permalink to &quot;ライセンス&quot;">​</a></h2><p>Ham Web は <a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT ライセンス</a> の下で公開されています。</p>`,31)])])}const u=s(l,[["render",t]]);export{k as __pageData,u as default};
